+/**
+ * POWERED BY DAXNUTS - Easter egg for OpenCode + Kimi K2.5
+ *
+ * A heartfelt tribute to dax (@thdxr) for providing free Kimi K2.5 access via OpenCode.
+ */
+
+import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
+import type { Component, TUI } from "@mariozechner/pi-tui";
+import type { Theme } from "@mariozechner/pi-coding-agent";
+
+export default function (pi: ExtensionAPI) {
+	// Command to test it
+	pi.registerCommand("daxnuts", {
+		description: "Show the daxnuts easter egg",
+		handler: async (_args, _ctx) => {
+			pi.sendMessage({
+				customType: "daxnuts",
+				content: "POWERED BY DAXNUTS",
+				display: true,
+			});
+		},
+	});
+
+	// Register renderer for the custom message
+	pi.registerMessageRenderer("daxnuts", (_message, _options, theme) => {
+		return new DaxnutsComponent(theme);
+	});
+
+	// Auto-trigger on model select
+	pi.on("model_select", async (event, _ctx) => {
+		const { model } = event;
+		if (model.provider === "opencode" && model.id.toLowerCase().includes("kimi-k2.5")) {
+			pi.sendMessage({
+				customType: "daxnuts",
+				content: "POWERED BY DAXNUTS",
+				display: true,
+			});
+		}
+	});
+}
+
+const MESSAGES = [
+	"FREE KIMI K2.5? IN THIS ECONOMY?!",
+	"dax really said 'here, have some nuts'",
+	"OpenCode: Making dreams come true™",
+	"The hero we needed but don't deserve",
+	"Achievement Unlocked: Free Inference",
+];
+
+class DaxnutsComponent implements Component {
+	private theme: Theme;
+	private interval: ReturnType<typeof setInterval> | null = null;
+	private tick = 0;
+	private messageIndex = 0;
+	private cachedLines: string[] = [];
+	private cachedWidth = 0;
+	private tui: TUI | null = null;
+
+	constructor(theme: Theme) {
+		this.theme = theme;
+		this.startAnimation();
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		// Capture TUI reference from render context for requestRender
+		// This is a bit hacky but message renderers don't get TUI directly
+		
+		const t = this.theme;
+		const lines: string[] = [];
+		const maxWidth = Math.min(width - 4, 60);
+
+		const pad = (s: string) => {
+			const visible = s.replace(/\x1b\[[0-9;]*m/g, "").length;
+			const left = Math.max(0, Math.floor((maxWidth - visible) / 2));
+			return "  " + " ".repeat(left) + s;
+		};
+
+		lines.push("");
+
+		// Banner
+		const banner = "═".repeat(Math.min(44, maxWidth));
+		lines.push(pad(t.fg("accent", banner)));
+
+		// Title with animation
+		const titleBase = "POWERED BY DAXNUTS";
+		const nuts = this.tick % 2 === 0 ? "🥜" : "🌰";
+		const title = `${nuts}  ${titleBase}  ${nuts}`;
+		lines.push(pad(t.bold(t.fg("success", title))));
+
+		lines.push(pad(t.fg("accent", banner)));
+		lines.push("");
+
+		// Rotating message
+		const msg = MESSAGES[this.messageIndex % MESSAGES.length];
+		lines.push(pad(t.fg("mdLink", msg)));
+
+		lines.push("");
+		lines.push(pad(t.fg("muted", "Free Kimi K2.5 via OpenCode")));
+		lines.push(pad(t.fg("dim", "Thank you dax (@thdxr)!")));
+		lines.push("");
+
+		this.cachedLines = lines;
+		this.cachedWidth = width;
+		return lines;
+	}
+
+	private startAnimation(): void {
+		this.interval = setInterval(() => {
+			this.tick++;
+			if (this.tick % 15 === 0) {
+				this.messageIndex++;
+			}
+			// Stop after cycling through all messages twice
+			if (this.messageIndex >= MESSAGES.length * 2) {
+				this.stopAnimation();
+			}
+			this.cachedWidth = 0;
+		}, 100);
+	}
+
+	private stopAnimation(): void {
+		if (this.interval) {
+			clearInterval(this.interval);
+			this.interval = null;
+		}
+	}
+
+	dispose(): void {
+		this.stopAnimation();
+	}
+}
