+	constructor(tui: TUI, theme: Theme, done: () => void) {
+		this.tui = tui;
+		this.theme = theme;
+		this.done = done;
+		this.startAnimation();
+	}
+
+	handleInput(_data: string): void {
+		this.stopAnimation();
+		this.done();
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		const t = this.theme;
+		const lines: string[] = [];
+		const maxWidth = Math.min(width - 4, 60);
+
+		const center = (s: string) => {
+			const visible = s.replace(/\x1b\[[0-9;]*m/g, "").length;
+			const left = Math.max(0, Math.floor((maxWidth - visible) / 2));
+			return "  " + " ".repeat(left) + s;
+		};
+
+		lines.push("");
+		lines.push("");
+
+		// Header
+		const nuts = this.tick % 4 < 2 ? "🥜" : "🌰";
+		lines.push(center(t.bold(t.fg("success", `${nuts} POWERED BY DAXNUTS ${nuts}`))));
+		lines.push("");
+
+		// ASCII art with color cycling
+		const artColor = this.tick % 6 < 3 ? "accent" : "muted";
+		for (const line of DAX_ART) {
+			lines.push(center(t.fg(artColor as any, line)));
+		}
+
+		lines.push("");
+
+		// Rotating message
+		const msg = MESSAGES[this.messageIndex % MESSAGES.length];
+		lines.push(center(t.fg("mdLink", msg)));
+
+		lines.push("");
+		lines.push(center(t.fg("dim", "Free Kimi K2.5 via OpenCode")));
+		lines.push(center(t.fg("dim", "github.com/opencode-ai • @thdxr")));
+		lines.push("");
+		lines.push(center(t.fg("muted", "Press any key to continue...")));
+		lines.push("");
+
+		this.cachedLines = lines;
+		this.cachedWidth = width;
+		return lines;
+	}
+
+	private startAnimation(): void {
+		this.interval = setInterval(() => {
+			this.tick++;
+			if (this.tick % 20 === 0) {
+				this.messageIndex++;
+			}
+			this.cachedWidth = 0;
+			this.tui.requestRender();
+		}, 100);
+	}
+
+	private stopAnimation(): void {
+		if (this.interval) {
+			clearInterval(this.interval);
+			this.interval = null;
+		}
+	}
+
+	dispose(): void {
+		this.stopAnimation();
+	}
+}
