+		const artColor = this.tick % 6 < 3 ? "accent" : "muted";
+		for (const line of DAX_ART) {
+			lines.push(center(t.fg(artColor as any, line)));
+		}
+
+		lines.push("");
+
+		// Rotating message
+		const msg = MESSAGES[this.messageIndex % MESSAGES.length];
+		lines.push(center(t.fg("mdLink", msg)));
+
+		lines.push("");
+		lines.push(center(t.fg("dim", "Free Kimi K2.5 via OpenCode")));
+		lines.push(center(t.fg("dim", "github.com/opencode-ai • @thdxr")));
+		lines.push("");
+		lines.push(center(t.fg("muted", "Press any key to continue...")));
+		lines.push("");
+
+		this.cachedLines = lines;
+		this.cachedWidth = width;
+		return lines;
+	}
+
+	private startAnimation(): void {
+		this.interval = setInterval(() => {
+			this.tick++;
+			if (this.tick % 20 === 0) {
+				this.messageIndex++;
+			}
+			this.cachedWidth = 0;
+			this.tui.requestRender();
+		}, 100);
+	}
+
+	private stopAnimation(): void {
+		if (this.interval) {
+			clearInterval(this.interval);
+			this.interval = null;
+		}
+	}
+
+	dispose(): void {
+		this.stopAnimation();
+	}
+}
