+				return new DaxnutsComponent(tui, theme, done);
+			});
+		}
+	});
+}
+
+const MESSAGES = [
+	"FREE KIMI K2.5? IN THIS ECONOMY?!",
+	"dax really said 'here, have some nuts'",
+	"OpenCode: Making dreams come true™",
+	"The hero we needed but don't deserve",
+	"Achievement Unlocked: Free Inference",
+];
+
+class DaxnutsComponent implements Component {
+	private tui: TUI;
+	private theme: Theme;
+	private done: () => void;
+	private interval: ReturnType<typeof setInterval> | null = null;
+	private tick = 0;
+	private messageIndex = 0;
+	private cachedLines: string[] = [];
+	private cachedWidth = 0;
+
+	constructor(tui: TUI, theme: Theme, done: () => void) {
+		this.tui = tui;
+		this.theme = theme;
+		this.done = done;
+		this.startAnimation();
+	}
+
+	onKey(key: string): boolean {
+		// Any key dismisses
+		this.stopAnimation();
+		this.done();
+		return true;
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		if (width === this.cachedWidth) {
+			return this.cachedLines;
+		}
+
+		const t = this.theme;
+		const lines: string[] = [];
+		const maxWidth = Math.min(width - 4, 60);
