+/**
+ * POWERED BY DAXNUTS - Easter egg for OpenCode + Kimi K2.5
+ *
+ * A heartfelt tribute to dax (@thdxr) for providing free Kimi K2.5 access via OpenCode.
+ */
+
+import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
+import type { Component, TUI } from "@mariozechner/pi-tui";
+import type { Theme } from "@mariozechner/pi-coding-agent";
+
+export default function (pi: ExtensionAPI) {
+	const showDaxnuts = async (ctx: { ui: any }) => {
+		await ctx.ui.custom<void>((tui: TUI, theme: Theme, _keybindings: any, done: () => void) => {
+			return new DaxnutsComponent(tui, theme, done);
+		});
+	};
+
+	pi.registerCommand("daxnuts", {
+		description: "Show the daxnuts easter egg",
+		handler: async (_args, ctx) => {
+			await showDaxnuts(ctx);
+		},
+	});
+
+	pi.on("model_select", async (event, ctx) => {
+		const { model } = event;
+		if (model.provider === "opencode" && model.id.toLowerCase().includes("kimi-k2.5")) {
+			await showDaxnuts(ctx);
+		}
+	});
+}
+
+// XBM image of dax: 32x32 pixels
+const WIDTH = 32;
+const HEIGHT = 32;
+const BITS = [
+	0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
+	0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
+	0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
+	0x00, 0x00, 0x00, 0x00, 0x00, 0xa0, 0x01, 0x00, 0x00, 0x00, 0x00, 0x00,
+	0x00, 0x00, 0xc0, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00,
+	0x00, 0x00, 0x00, 0x00, 0x00, 0x02, 0x00, 0x00, 0x00, 0x06, 0x00, 0x00,
+	0x00, 0xc6, 0x0f, 0x00, 0x00, 0xfe, 0x1f, 0x00, 0x00, 0x7e, 0x38, 0x00,
+	0x00, 0x7c, 0x20, 0x00, 0x00, 0xf8, 0x61, 0x00, 0x00, 0xf8, 0xf1, 0x00,
+	0x00, 0xf8, 0x7f, 0x00, 0x00, 0xf0, 0x7f, 0x00, 0x03, 0xe0, 0x3f, 0x00,
+	0x3f, 0xc0, 0x3f, 0x00, 0x31, 0x00, 0x1f, 0x00, 0x10, 0x00, 0x00, 0x00,
+	0x70, 0x00, 0x00, 0x00, 0xf0, 0x00, 0x00, 0x00,
+];
+
+const BYTES_PER_ROW = Math.ceil(WIDTH / 8);
+const DISPLAY_HEIGHT = Math.ceil(HEIGHT / 2);
+
+function getPixel(x: number, y: number): boolean {
+	if (y >= HEIGHT || x >= WIDTH) return false;
+	const byteIndex = y * BYTES_PER_ROW + Math.floor(x / 8);
+	const bitIndex = x % 8;
+	return ((BITS[byteIndex] >> bitIndex) & 1) === 1;
+}
+
+function getChar(x: number, row: number): string {
+	const upper = getPixel(x, row * 2);
+	const lower = getPixel(x, row * 2 + 1);
+	if (upper && lower) return "█";
+	if (upper) return "▀";
+	if (lower) return "▄";
+	return " ";
+}
+
+function buildImage(): string[] {
+	const lines: string[] = [];
+	for (let row = 0; row < DISPLAY_HEIGHT; row++) {
+		let line = "";
+		for (let x = 0; x < WIDTH; x++) {
+			line += getChar(x, row);
+		}
+		lines.push(line);
+	}
+	return lines;
+}
+
+class DaxnutsComponent implements Component {
+	private tui: TUI;
+	private theme: Theme;
+	private done: () => void;
+	private image: string[];
+	private cachedLines: string[] = [];
+	private cachedWidth = 0;
+
+	constructor(tui: TUI, theme: Theme, done: () => void) {
+		this.tui = tui;
+		this.theme = theme;
+		this.done = done;
+		this.image = buildImage();
+	}
+
+	handleInput(_data: string): void {
+		this.done();
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		if (width === this.cachedWidth) {
+			return this.cachedLines;
+		}
+
+		const t = this.theme;
+		const lines: string[] = [];
+
+		const center = (s: string) => {
+			const visible = s.replace(/\x1b\[[0-9;]*m/g, "").length;
+			const left = Math.max(0, Math.floor((width - visible) / 2));
+			return " ".repeat(left) + s;
+		};
+
+		lines.push("");
+
+		// Image
+		for (const line of this.image) {
+			lines.push(center(t.fg("accent", line)));
+		}
+
+		lines.push("");
+		lines.push(center(t.fg("success", '"Powered by daxnuts"')));
+		lines.push(center(t.fg("muted", "— @thdxr")));
+		lines.push("");
+		lines.push(center(t.fg("dim", "Try OpenCode")));
+		lines.push(center(t.fg("mdLink", "https://opencode.ai")));
+		lines.push("");
+		lines.push(center(t.fg("muted", "Press any key...")));
+		lines.push("");
+
+		this.cachedLines = lines;
+		this.cachedWidth = width;
+		return lines;
+	}
+
+	dispose(): void {}
+}
