+/**
+ * POWERED BY DAXNUTS - Easter egg for OpenCode + Kimi K2.5
+ *
+ * A heartfelt (and slightly unhinged) tribute to dax (@thdxr) for providing
+ * free Kimi K2.5 access via OpenCode. This is what peak gratitude looks like.
+ */
+
+import type { Component, TUI } from "@mariozechner/pi-tui";
+import { theme } from "../theme/theme.js";
+
+const DAXNUTS_MESSAGES = [
+	"🥜 POWERED BY DAXNUTS 🥜",
+	"FREE KIMI K2.5? IN THIS ECONOMY?!",
+	"dax really said 'here, have some nuts'",
+	"OpenCode: Making dreams come true™",
+	"Thank you dax, very cool!",
+	"This message brought to you by DAXNUTS",
+	"The hero we needed but don't deserve",
+	"π loves OpenCode (platonically)",
+	"No API key? No problem! (thanks dax)",
+	"Achievement Unlocked: Free Inference",
+];
+
+const SPARKLE_CHARS = ["✨", "⭐", "🌟", "💫", "✧", "★", "☆", "✦", "✶", "✹"];
+
+// ASCII art nut (stylized)
+const NUT_ART = [
+	"      ___      ",
+	"     /   \\     ",
+	"    | 🥜  |    ",
+	"     \\___/     ",
+	"       |       ",
+	"      ~~~      ",
+];
+
+type AnimationPhase = "intro" | "message" | "sparkle" | "nut" | "finale";
+
+export class DaxnutsComponent implements Component {
+	private ui: TUI;
+	private interval: ReturnType<typeof setInterval> | null = null;
+	private phase: AnimationPhase = "intro";
+	private tick = 0;
+	private currentMessage = 0;
+	private sparklePositions: number[] = [];
+	private displayWidth = 60;
+	private cachedLines: string[] = [];
+	private cachedWidth = 0;
+	private cachedTick = -1;
+
+	constructor(ui: TUI) {
+		this.ui = ui;
+		this.startAnimation();
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		if (width === this.cachedWidth && this.cachedTick === this.tick) {
+			return this.cachedLines;
+		}
+
+		this.displayWidth = Math.min(width - 2, 70);
+		this.cachedLines = this.renderFrame();
+		this.cachedWidth = width;
+		this.cachedTick = this.tick;
+
+		return this.cachedLines;
+	}
+
+	private renderFrame(): string[] {
+		const lines: string[] = [];
+		const pad = (s: string, w: number) => {
+			const visible = s.replace(/\x1b\[[0-9;]*m/g, "").length;
+			const padding = Math.max(0, w - visible);
+			return ` ${s}${" ".repeat(padding)}`;
+		};
+
+		switch (this.phase) {
+			case "intro": {
+				// Typewriter effect for the banner
+				const banner = "═══════════════════════════════════════";
+				const title = "🥜  P O W E R E D   B Y   D A X N U T S  🥜";
+				const progress = Math.min(this.tick * 2, banner.length);
+				const partialBanner = banner.slice(0, progress);
+
+				lines.push(pad(theme.fg("accent", partialBanner), this.displayWidth));
+				if (this.tick > banner.length / 4) {
+					const titleProgress = Math.min((this.tick - banner.length / 4) * 2, title.length);
+					lines.push(pad(theme.bold(theme.fg("success", title.slice(0, titleProgress))), this.displayWidth));
+				}
+				if (this.tick > banner.length / 2) {
+					lines.push(pad(theme.fg("accent", partialBanner), this.displayWidth));
+				}
+				break;
+			}
+
+			case "message": {
+				// Show rotating messages with bounce effect
+				const banner = "═══════════════════════════════════════";
+				const title = "🥜  P O W E R E D   B Y   D A X N U T S  🥜";
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad(theme.bold(theme.fg("success", title)), this.displayWidth));
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad("", this.displayWidth));
+
+				const msg = DAXNUTS_MESSAGES[this.currentMessage % DAXNUTS_MESSAGES.length];
+				const bounce = Math.sin(this.tick * 0.3) > 0 ? "  " : "";
+				lines.push(pad(bounce + theme.fg("mdLink", msg), this.displayWidth));
+				break;
+			}
+
+			case "sparkle": {
+				// Sparkle rain effect
+				const banner = "═══════════════════════════════════════";
+				const title = "🥜  P O W E R E D   B Y   D A X N U T S  🥜";
+
+				// Generate sparkle line
+				let sparkleLine = "";
+				for (let i = 0; i < this.displayWidth - 2; i++) {
+					if (this.sparklePositions.includes(i)) {
+						sparkleLine += SPARKLE_CHARS[Math.floor(Math.random() * SPARKLE_CHARS.length)];
+					} else {
+						sparkleLine += " ";
+					}
+				}
+
+				lines.push(pad(theme.fg("warning", sparkleLine), this.displayWidth));
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad(theme.bold(theme.fg("success", title)), this.displayWidth));
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad(theme.fg("warning", sparkleLine), this.displayWidth));
+				break;
+			}
+
+			case "nut": {
+				// Show the nut art
+				for (const line of NUT_ART) {
+					const colored = this.tick % 2 === 0 ? theme.fg("warning", line) : theme.fg("success", line);
+					lines.push(pad(colored, this.displayWidth));
+				}
+				const msg = "Thanks @thdxr for the free Kimi K2.5! 🙏";
+				lines.push(pad(theme.fg("muted", msg), this.displayWidth));
+				break;
+			}
+
+			case "finale": {
+				// Final static display
+				const banner = "═══════════════════════════════════════";
+				const title = "🥜  P O W E R E D   B Y   D A X N U T S  🥜";
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad(theme.bold(theme.fg("success", title)), this.displayWidth));
+				lines.push(pad(theme.fg("accent", banner), this.displayWidth));
+				lines.push(pad("", this.displayWidth));
+				lines.push(
+					pad(theme.fg("muted", "Free Kimi K2.5 via OpenCode • github.com/opencode-ai"), this.displayWidth),
+				);
+				lines.push(pad(theme.fg("dim", "Thank you dax (@thdxr) for making this possible!"), this.displayWidth));
+				break;
+			}
+		}
+
+		return lines;
+	}
+
+	private startAnimation(): void {
+		// Initialize sparkle positions
+		for (let i = 0; i < 15; i++) {
+			this.sparklePositions.push(Math.floor(Math.random() * (this.displayWidth - 2)));
+		}
+
+		this.interval = setInterval(() => {
+			this.tick++;
+
+			// Phase transitions
+			if (this.phase === "intro" && this.tick > 25) {
+				this.phase = "message";
+				this.tick = 0;
+			} else if (this.phase === "message" && this.tick > 20) {
+				this.currentMessage++;
+				if (this.currentMessage >= 3) {
+					this.phase = "sparkle";
+					this.tick = 0;
+				} else {
+					this.tick = 0;
+				}
+			} else if (this.phase === "sparkle" && this.tick > 15) {
+				this.phase = "nut";
+				this.tick = 0;
+			} else if (this.phase === "nut" && this.tick > 20) {
+				this.phase = "finale";
+				this.stopAnimation();
+			}
+
+			// Update sparkle positions for sparkle phase
+			if (this.phase === "sparkle" && this.tick % 2 === 0) {
+				this.sparklePositions = this.sparklePositions.map(
+					() => Math.floor(Math.random() * (this.displayWidth - 2)),
+				);
+			}
+
+			this.ui.requestRender();
+		}, 80);
+	}
+
+	private stopAnimation(): void {
+		if (this.interval) {
+			clearInterval(this.interval);
+			this.interval = null;
+		}
+	}
+
+	dispose(): void {
+		this.stopAnimation();
+	}
+}
