+		this.stopAnimation();
+		this.done();
+		return true;
+	}
+
+	invalidate(): void {
+		this.cachedWidth = 0;
+	}
+
+	render(width: number): string[] {
+		if (width === this.cachedWidth) {
+			return this.cachedLines;
+		}
+
+		const t = this.theme;
+		const lines: string[] = [];
