+	const pixels = parseImage();
+	const lines: string[] = [];
+
+	// Use half-block chars: ▄ with bg=top pixel, fg=bottom pixel
+	for (let row = 0; row < HEIGHT; row += 2) {
+		let line = "";
+		for (let x = 0; x < WIDTH; x++) {
+			const top = pixels[row][x];
+			const bottom = pixels[row + 1]?.[x] ?? top;
