+export default function (pi: ExtensionAPI) {
+	const showDaxnuts = async (ctx: { ui: any }) => {
+		await ctx.ui.custom<void>((tui: TUI, theme: Theme, _keybindings: any, done: () => void) => {
+			return new DaxnutsComponent(tui, theme, done);
+		});
+	};
+
+	pi.registerCommand("daxnuts", {
+		description: "Show the daxnuts easter egg",
+		handler: async (_args, ctx) => {
+			await showDaxnuts(ctx);
+		},
+	});
+
+	pi.on("model_select", async (event, ctx) => {
+		const { model } = event;
+		if (model.provider === "opencode" && model.id.toLowerCase().includes("kimi-k2.5")) {
+			await showDaxnuts(ctx);
+		}
+	});
+}
+
+// 32x32 RGB image of dax, hex encoded (3 bytes per pixel)
+const DAX_HEX = "";
+
+const WIDTH = 32;
+const HEIGHT = 32;
+
+function parseImage(): number[][][] {
+	const pixels: number[][][] = [];
+	for (let y = 0; y < HEIGHT; y++) {
+		const row: number[][] = [];
+		for (let x = 0; x < WIDTH; x++) {
+			const idx = (y * WIDTH + x) * 6;
+			const r = parseInt(DAX_HEX.slice(idx, idx + 2), 16);
+			const g = parseInt(DAX_HEX.slice(idx + 2, idx + 4), 16);
+			const b = parseInt(DAX_HEX.slice(idx + 4, idx + 6), 16);
+			row.push([r, g, b]);
+		}
+		pixels.push(row);
+	}
+	return pixels;
+}
+
+function rgb(r: number, g: number, b: number, bg = false): string {
+	return `\x1b[${bg ? 48 : 38};2;${r};${g};${b}m`;
+}
+
+const RESET = "\x1b[0m";
+
+function buildImage(): string[] {
+	const pixels = parseImage();
+	const lines: string[] = [];
+
+	// Use half-block chars: ▄ with bg=top pixel, fg=bottom pixel
+	for (let row = 0; row < HEIGHT; row += 2) {
+		let line = "";
+		for (let x = 0; x < WIDTH; x++) {
+			const top = pixels[row][x];
+			const bottom = pixels[row + 1]?.[x] ?? top;
+			line += rgb(bottom[0], bottom[1], bottom[2]) + rgb(top[0], top[1], top[2], true) + "▄";
+		}
+		line += RESET;
+		lines.push(line);
+	}
+	return lines;
+}
+
+class DaxnutsComponent implements Component {
+	private tui: TUI;
+	private theme: Theme;
+	private done: () => void;
+	private image: string[];
+	private interval: ReturnType<typeof setInterval> | null = null;
+	private tick = 0;
+	private maxTicks = 25; // ~2 seconds at 80ms
+	private cachedLines: string[] = [];
+	private cachedWidth = 0;
+	private cachedTick = -1;
+
+	constructor(tui: TUI, theme: Theme, done: () => void) {
+		this.tui = tui;
+		this.theme = theme;
+		this.done = done;
